import { useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function ForgotPassword() {
    const [data, setData] = useState({ email: "", newPassword: "" });
    const navigate = useNavigate();

    const validate = () => {
        // Reuse logic or keep simple as user requested "make the user to change their password"
        // But user said "email should be in a valid format" generally.
        // I will apply the same strict rules here for consistency.
        const emailRegex = /^[a-zA-Z0-9._%+-]+@gmail\.com$/;
        if (!emailRegex.test(data.email)) {
            alert("Invalid Email: Must be a valid @gmail.com address.");
            return false;
        }
        const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{6,}$/;
        if (!passwordRegex.test(data.newPassword)) {
            alert("Invalid Password: Must be at least 6 chars, include uppercase, lowercase, number, and special character.");
            return false;
        }
        return true;
    };

    const submit = async () => {
        if (!validate()) return;

        try {
            await axios.post("/auth/reset-password", data);
            alert("Password updated successfully! Please login with new password.");
            navigate("/login");
        } catch (err) {
            console.error("Reset Error:", err.response?.data || err.message);
            alert(err.response?.data?.message || "Failed to update password. Check email.");
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <h2 className="auth-title">Reset Password</h2>
                <p className="auth-subtitle">Enter your email and new password</p>

                <div className="input-group">
                    <input
                        placeholder="Email Address (@gmail.com)"
                        onChange={e => setData({ ...data, email: e.target.value })}
                    />
                </div>

                <div className="input-group">
                    <input
                        type="password"
                        placeholder="New Password"
                        onChange={e => setData({ ...data, newPassword: e.target.value })}
                    />
                </div>

                <button className="btn-primary" onClick={submit}>Update Password</button>

                <p className="auth-link">
                    Remembered it? <span onClick={() => navigate("/login")}>Login here</span>
                </p>
            </div>
        </div>
    );
}
